item.arguments:
{"command":"# Find any agent session files from today's PM build window (after 19:00 UTC = noon PT)
find ~/agents/ -name "*.jsonl" -newer /tmp/pm-marker 2>/dev/null | head -20; 
# Alternative: just list recent JSONL files
find ~/agents/ -name "*.jsonl" -mmin -480 2>/dev/null | head -30"}
